class Pizza:
    def __init__(self, toppings):
        self.toppings = toppings

    def describe(self):                  # instance method: uses self
        return f"Pizza with {', '.join(self.toppings)}"

    @classmethod
    def margherita(cls):                 # alternative constructor: uses cls
        return cls(["tomato", "mozzarella", "basil"])

    @staticmethod
    def is_vegetarian(toppings):         # no self/cls: a plain helper
        return "pepperoni" not in toppings

p = Pizza.margherita()
print(p.describe())                      # Pizza with tomato, mozzarella, basil
print(Pizza.is_vegetarian(["tomato"]))   # True

class Vector:
    def __init__(self, x, y):
        self.x, self.y = x, y

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    def __add__(self, other):        # enables v1 + v2
        return Vector(self.x + other.x, self.y + other.y)

    def __eq__(self, other):         # enables v1 == v2
        return (self.x, self.y) == (other.x, other.y)

    def __abs__(self):               # enables abs(v)
        return (self.x ** 2 + self.y ** 2) ** 0.5

v = Vector(1, 2) + Vector(3, 4)
print(v)              # Vector(4, 6)
print(abs(Vector(3, 4)))   # 5.0
print(Vector(1, 2) == Vector(1, 2))  # True

class Playlist:
    def __init__(self, songs):
        self._songs = list(songs)

    def __len__(self):               # enables len(playlist)
        return len(self._songs)

    def __getitem__(self, i):        # enables playlist[i] AND iteration
        return self._songs[i]

pl = Playlist(["Song A", "Song B", "Song C"])
print(len(pl))        # 3
print(pl[1])          # Song B
for song in pl:       # works because __getitem__ supports iteration
    print(song)

