# money.py
class Money:
    def __init__(self, dollars=0, cents=0):
        self.cents = dollars * 100 + cents   # store everything as cents

    def __repr__(self):
        return f"Money(cents={self.cents})"

    def __str__(self):
        return f"${self.cents / 100:.2f}"

m = Money(4, 50)
print(repr(m))   # Money(cents=450)
print(m)         # $4.50

    def __add__(self, other):
        return Money(cents=self.cents + other.cents)

# with __add__ added to the class:
print(Money(4, 50) + Money(1, 75))   # $6.25

    def __eq__(self, other):
        return self.cents == other.cents

    def __lt__(self, other):
        return self.cents < other.cents

    def __hash__(self):
        return hash(self.cents)

# now Money works in sets and as dict keys
prices = {Money(1, 0): "cheap", Money(100, 0): "pricey"}
print(prices[Money(1, 0)])          # cheap
print(Money(2, 0) < Money(5, 0))    # True
print(Money(3, 0) == Money(3, 0))   # True

from functools import total_ordering

@total_ordering
class Money:
    def __init__(self, dollars=0, cents=0):
        self.cents = dollars * 100 + cents
    def __eq__(self, other):
        return self.cents == other.cents
    def __lt__(self, other):
        return self.cents < other.cents
    def __repr__(self):
        return f"${self.cents / 100:.2f}"

wallet = [Money(5), Money(1, 50), Money(0, 99)]
print(sorted(wallet))   # [$0.99, $1.50, $5.00]
print(Money(5) >= Money(1))   # True (derived by total_ordering)

