# shapes.py
from abc import ABC, abstractmethod

class Shape(ABC):
    def __init__(self, name):
        self.name = name

    @abstractmethod
    def area(self):
        ...

    def describe(self):
        return f"{self.name} has area {self.area():.2f}"

# Shape("x") would raise TypeError: can't instantiate abstract class

import math

class Circle(Shape):
    def __init__(self, radius):
        super().__init__("Circle")
        self.radius = radius
    def area(self):
        return math.pi * self.radius ** 2

class Rectangle(Shape):
    def __init__(self, w, h):
        super().__init__("Rectangle")
        self.w, self.h = w, h
    def area(self):
        return self.w * self.h

print(Circle(2).describe())        # Circle has area 12.57
print(Rectangle(3, 4).describe())  # Rectangle has area 12.00

