class Temperature:
    def __init__(self, celsius):
        self._celsius = celsius

    @property
    def celsius(self):              # getter with validation on set
        return self._celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError("below absolute zero")
        self._celsius = value

    @property
    def fahrenheit(self):           # computed, read-only (no setter)
        return self._celsius * 9 / 5 + 32

t = Temperature(25)
print(t.fahrenheit)   # 77.0  (accessed like an attribute, not t.fahrenheit())
t.celsius = 30        # goes through the setter
# t.fahrenheit = 100  # AttributeError: no setter (read-only)
# t.celsius = -300    # ValueError: below absolute zero

