class Account:
    def __init__(self, balance=0):
        self.balance = balance        # goes through the setter below

    @property
    def balance(self):
        return self._balance

    @balance.setter
    def balance(self, value):
        if value < 0:
            raise ValueError("balance cannot be negative")
        self._balance = value

a = Account(100)
a.balance = 150       # same syntax, now validated
print(a.balance)      # 150
# a.balance = -5      # ValueError: balance cannot be negative

    @property
    def is_overdrawn(self):
        return self._balance == 0

a = Account(0)
print(a.is_overdrawn)   # True
